const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const cors = require('cors');

const app = express();

// Security middleware
app.use(helmet()); // Set security headers

// CORS configuration
app.use(cors({
  origin: process.env.ALLOWED_ORIGINS?.split(',') || ['http://localhost:3000'],
  credentials: true,
}));

// Rate limiting
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // Limit each IP to 100 requests per windowMs
  message: 'Too many requests from this IP, please try again later.',
  headers: true,
});

app.use(limiter);

// Body parsing with size limits
app.use(express.json({
  limit: '10kb', // Limit JSON payload size
}));

app.use(express.urlencoded({
  extended: true,
  limit: '10kb', // Limit urlencoded payload size
}));

// Input validation middleware
const validateIdParam = (req, res, next) => {
  const { id } = req.params;

  if (id !== undefined) {
    const idNum = parseInt(id, 10);
    if (isNaN(idNum) || idNum <= 0) {
      return res.status(400).json({
        error: 'Invalid ID parameter. ID must be a positive integer.',
      });
    }
    // Store validated ID in request object
    req.validated = req.validated || {};
    req.validated.id = idNum;
  }

  next();
};

// Health check endpoint
app.get('/health', (req, res) => {
  try {
    res.json({ 
      status: 'ok', 
      timestamp: new Date().toISOString() 
    });
  } catch (error) {
    console.error('Health check error:', error);
    res.status(500).json({ 
      error: 'Health check failed',
      timestamp: new Date().toISOString()
    });
  }
});

// Users endpoint - with potential for ID parameter
app.get('/users', validateIdParam, (req, res) => {
  try {
    const mockUsers = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    // If ID is provided, return specific user
    if (req.validated?.id) {
      const user = mockUsers.find(u => u.id === req.validated.id);
      if (!user) {
        return res.status(404).json({
          error: `User with ID ${req.validated.id} not found`
        });
      }
      return res.json(user);
    }

    // Otherwise return all users
    res.json(mockUsers);
  } catch (error) {
    console.error('Error fetching users:', error);
    res.status(500).json({ 
      error: 'Internal server error while fetching users'
    });
  }
});

// Catch 404 errors
app.use('*', (req, res) => {
  res.status(404).json({
    error: `Route ${req.method} ${req.originalUrl} not found`
  });
});

// Error handling middleware (should be last)
app.use((err, req, res, next) => {
  console.error('Unhandled error:', err);

  // Default error response
  const errorResponse = {
    error: 'Internal server error',
    timestamp: new Date().toISOString()
  };

  // In development, include error details
  if (process.env.NODE_ENV === 'development') {
    errorResponse.details = err.message;
    errorResponse.stack = err.stack;
  }

  res.status(500).json(errorResponse);
});

// Graceful shutdown
process.on('SIGTERM', () => {
  console.log('SIGTERM received: closing HTTP server');
  process.exit(0);
});

process.on('SIGINT', () => {
  console.log('SIGINT received: closing HTTP server');
  process.exit(0);
});

const PORT = process.env.PORT || 3000;

app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
  console.log(`Environment: ${process.env.NODE_ENV || 'development'}`);
});

module.exports = app;

