const mongoSanitize = require('express-mongo-sanitize');

const app = express();

// Security middleware
app.use(helmet()); // Sets various HTTP headers for security
app.use(xss()); // Sanitizes user input for XSS protection
app.use(mongoSanitize()); // Prevents MongoDB operator injection

// CORS configuration
const corsOptions = {
  origin: process.env.ALLOWED_ORIGINS || 'http://localhost:3000',
  methods: ['GET', 'POST', 'PUT', 'DELETE'],
  allowedHeaders: ['Content-Type', 'Authorization'],
};
app.use(cors(corsOptions));

// Rate limiting
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // Limit each IP to 100 requests per windowMs
  message: 'Too many requests from this IP, please try again later',
  standardHeaders: true,
  legacyHeaders: false,
});

app.use('/api/', limiter); // Apply rate limiting to API routes

// Body parsing with size limits
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: true, limit: '10kb' }));

// Request timeout
app.use((req, res, next) => {
  // Set timeout header
  req.setTimeout(30000, () => {
    res.status(408).json({
      error: 'Request timeout',
      message: 'The request took too long to process'
    });
  });
  next();
});

// Health check with basic response
app.get('/health', (req, res) => {
  try {
    // Validate query parameters if any
    if (req.query.verbose !== undefined && req.query.verbose !== 'true' && req.query.verbose !== 'false') {
      return res.status(400).json({
        error: 'Invalid parameter',
        message: 'The "verbose" parameter must be "true" or "false"'
      });
    }

    const response = { status: 'ok', timestamp: new Date().toISOString() };

    // Add additional info if verbose requested
    if (req.query.verbose === 'true') {
      response.environment = process.env.NODE_ENV || 'development';
      response.version = '1.0.0'; // Could be read from package.json
    }

    res.json(response);
  } catch (error) {
    console.error('Health check error:', error);
    res.status(500).json({
      error: 'Internal server error',
      message: 'An unexpected error occurred'
    });
  }
});

// Users endpoint with input validation
app.get('/users', (req, res) => {
  try {
    // Input validation
    const page = req.query.page ? parseInt(req.query.page) : 1;
    const limit = req.query.limit ? parseInt(req.query.limit) : 10;

    // Validate input ranges
    if (isNaN(page) || page < 1) {
      return res.status(400).json({
        error: 'Invalid parameter',
        message: 'Page must be a positive integer'
      });
    }

    if (isNaN(limit) || limit < 1 || limit > 100) {
      return res.status(400).json({
        error: 'Invalid parameter',
        message: 'Limit must be a positive integer between 1 and 100'
      });
    }

    // Simulated data (in real app, this would come from a database)
    const mockUsers = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    // Calculate pagination
    const startIndex = (page - 1) * limit;
    const paginatedUsers = mockUsers.slice(startIndex, startIndex + limit);

    // Return response with pagination metadata
    res.json({
      data: paginatedUsers,
      pagination: {
        page,
        limit,
        total: mockUsers.length,
        pages: Math.ceil(mockUsers.length / limit)
      }
    });

  } catch (error) {
    console.error('Users endpoint error:', error);
    res.status(500).json({
      error: 'Internal server error',
      message: 'An unexpected error occurred while fetching users'
    });
  }
});

// Handle 404 for undefined routes
app.use('*', (req, res) => {
  res.status(404).json({
    error: 'Not found',
    message: `The route ${req.method} ${req.baseUrl}${req.url} does not exist`
  });
});

// Global error handler
app.use((error, req, res, next) => {
  console.error('Unhandled error:', error);

  // Default error response
  const errorResponse = {
    error: 'Internal server error',
    message: 'An unexpected error occurred'
  };

  // Set status code (use error.status or default to 500)
  const statusCode = error.status || 500;
  res.status(statusCode).json(errorResponse);
});

// Graceful shutdown
const server = app.listen(3000, () => {
  console.log('Server running on port 3000');
});

// Handle unhandled promise rejections
process.on('unhandledRejection', (err) => {
  console.error('Unhandled Promise Rejection:', err);
  server.close(() => process.exit(1));
});

// Handle uncaught exceptions
process.on('uncaughtException', (err) => {
  console.error('Uncaught Exception:', err);
  server.close(() => process.exit(1));
});

module.exports = app;

