const express = require('express');
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');
const cors = require('cors');
const yup = require('yup');

const app = express();

// Security middleware
app.use(helmet()); // Security headers
app.use(cors({
  origin: process.env.ALLOWED_ORIGINS || '*', // Configure for production
  optionsSuccessStatus: 200
}));

// Rate limiting
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // Limit each IP to 100 requests per window
  message: 'Too many requests from this IP, please try again later.',
  standardHeaders: true, // Return rate limit info in the RateLimit-* headers
  legacyHeaders: false, // Disable the X-RateLimit-* headers
});

// Apply rate limit to all requests
app.use(limiter);

// Request parsing with security limits
app.use(express.json({
  limit: '10kb' // Prevent large payload attacks
}));
app.use(express.urlencoded({ extended: true, limit: '10kb' }));

// Input validation schema for query parameters
const healthQuerySchema = yup.object().shape({
  // Add validated parameters if needed
  verbose: yup.boolean().default(false)
});

const usersQuerySchema = yup.object().shape({
  limit: yup.number().integer().min(1).max(100).default(10),
  offset: yup.number().integer().min(0).default(0)
});

// Enhanced health check with input validation
app.get('/health', async (req, res, next) => {
  try {
    // Validate query parameters
    let validatedQuery;
    try {
      validatedQuery = await healthQuerySchema.validate(req.query, { abortEarly: false });
    } catch (validationError) {
      return res.status(400).json({
        error: 'Invalid query parameters',
        details: validationError.errors
      });
    }

    const response = {
      status: 'ok', 
      timestamp: new Date().toISOString()
    };

    // Add verbose information if requested
    if (validatedQuery.verbose) {
      response.environment = process.env.NODE_ENV || 'development';
      response uptime = process.uptime();
    }

    res.json(response);
  } catch (error) {
    // This will be caught by the error handling middleware
    next(error);
  }
});

// Users endpoint with input validation and error handling
app.get('/users', async (req, res, next) => {
  try {
    // Validate query parameters
    let validatedQuery;
    try {
      validatedQuery = await usersQuerySchema.validate(req.query, { abortEarly: false });
    } catch (validationError) {
      return res.status(400).json({
        error: 'Invalid query parameters',
        details: validationError.errors
      });
    }

    // Simulated user data (in a real app, this would come from a database)
    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    // Apply pagination if supported
    const { limit, offset } = validatedQuery;
    const paginatedUsers = users.slice(offset, offset + limit);

    res.json({
      data: paginatedUsers,
      pagination: {
        limit,
        offset,
        total: users.length,
        hasNext: offset + limit < users.length
      }
    });
  } catch (error) {
    next(error);
  }
});

// 404 handler for undefined routes
app.use('*', (req, res, next) => {
  const error = new Error(`Route ${req.originalUrl} not found`);
  error.statusCode = 404;
  next(error);
});

// Centralized error handling middleware
app.use((error, req, res, next) => {
  // Log error (in production, use a proper logging library)
  console.error('Error:', error.message);

  // Set default error values
  const statusCode = error.statusCode || 500;
  const message = error.message || 'Internal Server Error';

  // Don't leak sensitive error details in production
  const errorResponse = { error: message };

  // Add stack trace only in development
  if (process.env.NODE_ENV === 'development') {
    errorResponse.stack = error.stack;
  }

  res.status(statusCode).json(errorResponse);
});

// Graceful shutdown
process.on('unhandledRejection', (error) => {
  console.error('Unhandled Rejection:', error);
  process.exit(1);
});

process.on('uncaughtException', (error) => {
  console.error('Uncaught Exception:', error);
  process.exit(1);
});

const PORT = process.env.PORT || 3000;
const server = app.listen(PORT, () => {
  console.log(`Server running on port ${PORT} in ${process.env.NODE_ENV || 'development'} mode`);
});

module.exports = app;
module.exports.server = server;

