const sanitizeInput = (req, res, next) => {
  // Remove any potential malicious characters or scripts
  if (req.query) {
    Object.keys(req.query).forEach(key => {
      if (typeof req.query[key] === 'string') {
        req.query[key] = req.query[key].trim();
      }
    });
  }
  next();
};

