/**
 * Input validation middleware
 */
const validator = require('validator');

/**
 * Sanitizes input by removing dangerous characters
 * @param {string} str - Input string
 * @returns {string} Sanitized string
 */
const sanitizeInput = (str) => {
  if (typeof str !== 'string') return str;
  return str
    .trim()
    .replace(/<[\/!?][^>]+>/g, '') // Remove HTML tags
    .replace(/javascript:/gi, '') // Remove javascript: exploits
    .replace(/<script[^>]*>[^<]*<\/script>/gi, ''); // Remove script tags
};

/**
 * Validates and sanitizes user input
 * @param {Object} input - User input object
 * @param {Object} rules - Validation rules
 * @returns {Object} { isValid, errors, sanitizedData }
 */
const validateInput = (input, rules) => {
  const errors = {};
  const sanitizedData = { ...input };

  for (const [field, rule] of Object.entries(rules)) {
    let value = input[field];

    // Skip validation for undefined/null values if not required
    if (value === undefined || value === null) {
      if (rule.required) {
        errors[field] = `${field} is required`;
      }
      continue;
    }

    // Sanitize first
    if (typeof value === 'string') {
      sanitizedData[field] = sanitizeInput(value);
      value = sanitizedData[field];
    }

    // Apply validation rules
    if (rule.required && (value === '' || value === null || value === undefined)) {
      errors[field] = `${field} is required`;
    }

    if (rule.minLength && value.length < rule.minLength) {
      errors[field] = `${field} must be at least ${rule.minLength} characters long`;
    }

    if (rule.maxLength && value.length > rule.maxLength) {
      errors[field] = `${field} must be at most ${rule.maxLength} characters long`;
    }

    if (rule.type) {
      if (rule.type === 'email' && !validator.isEmail(value)) {
        errors[field] = `${field} must be a valid email address`;
      }

      if (rule.type === 'number' && isNaN(Number(value))) {
        errors[field] = `${field} must be a valid number`;
      }

      if (rule.type === 'string' && typeof value !== 'string') {
        errors[field] = `${field} must be a string`;
      }
    }

    if (rule.pattern && !rule.pattern.test(value)) {
      errors[field] = `${field} format is invalid`;
    }
  }

  return {
    isValid: Object.keys(errors).length === 0,
    errors,
    sanitizedData
  };
};

module.exports = {
  validateInput,
  sanitizeInput
};

/**
 * Centralized error handling middleware
 */

/**
 * Handles application errors and sends appropriate responses
 * @param {Error} err - Error object
 * @param {Object} req - Express request object
 * @param {Object} res - Express response object
 * @param {Function} next - Next middleware function
 */
const errorHandler = (err, req, res, next) => {
  // Log the error (in production, use a proper logging service)
  console.error('Error:', err.message, {\n    stack: err.stack,\n    url: req.url,\n    method: req.method,\n    ip: req.ip,\n    headers: req.headers\n  });

  // Determine the status code
  const statusCode = err.statusCode || err.status || 500;

  // Determine the error message to send
  // In production, don't send detailed error messages
  const isProd = process.env.NODE_ENV === 'production';
  const message = isProd && statusCode === 500
    ? 'Internal Server Error'
    : err.message || 'Something went wrong';

  // Send the error response
  res.status(statusCode).json({
    success: false,
    message: message,
    // Only include stack in development
    ...(process.env.NODE_ENV === 'development' && { stack: err.stack })
  });
};

/**
 * Creates an AppError class for consistent error handling
 * @param {string} message - Error message
 * @param {number} statusCode - HTTP status code
 * @returns {Error} An error object with statusCode property
 */
const AppError = (message, statusCode) => {
  const error = new Error(message);
  error.statusCode = statusCode;
  error.isOperational = true; // Mark as operational error

  // Capture stack trace
  Error.captureStackTrace(error, AppError);

  return error;
};

/**
 * Handles 404 errors for undefined routes
 * @param {Object} req - Express request object
 * @param {Object} res - Express response object
 * @param {Function} next - Next middleware function
 */
const notFoundHandler = (req, res, next) => {
  next(AppError(`Can't find ${req.originalUrl} on this server!`, 404));
};

module.exports = {
  errorHandler,
  AppError,
  notFoundHandler
};

/**
 * Security utilities for input sanitization
 */

/**
 * Sanitizes user input to prevent XSS and other injection attacks
 * @param {any} data - Input data to sanitize
 * @returns {any} Sanitized data
 */
const sanitize = (data) => {
  if (data === null || data === undefined) {
    return data;
  }

  // Handle strings
  if (typeof data === 'string') {
    return data
      .trim()
      .replace(/<script[^>]*>.*?<\/script>/gi, '') // Remove script tags
      .replace(/<iframe[^>]*>.*?<\/iframe>/gi, '') // Remove iframe tags
      .replace(/<object[^>]*>.*?<\/object>/gi, '') // Remove object tags
      .replace(/<embed[^>]*>.*?<\/embed>/gi, '') // Remove embed tags
      .replace(/javascript:/gi, '') // Remove javascript: protocol
      .replace(/vbscript:/gi, '') // Remove vbscript: protocol
      .replace(/data:/gi, '') // Remove data: protocol
      .replace(/on\w+\s*=('|"|`)/gi, '') // Remove event handlers (onclick, onload, etc.)
      .replace(/expression\s*\(/gi, '') // Remove CSS expressions
      .replace(/behavior\s*:\s*url\(/gi, ''); // Remove CSS behaviors
  }

  // Handle arrays
  if (Array.isArray(data)) {
    return data.map(item => sanitize(item));
  }

  // Handle objects
  if (typeof data === 'object') {
    const sanitized = {};
    for (const key in data) {
      if (Object.prototype.hasOwnProperty.call(data, key)) {
        sanitized[key] = sanitize(data[key]);
      }
    }
    return sanitized;
  }

  // Return other types unchanged
  return data;
};

/**
 * Validates if input contains potentially dangerous patterns
 * @param {string} str - String to validate
 * @returns {boolean} True if clean, false if potentially dangerous
 */
const isCleanInput = (str) => {
  if (typeof str !== 'string') return true;

  // Patterns that are potentially dangerous
  const dangerousPatterns = [
    /<script/i,
    /javascript:/i,
    /vbscript:/i,
    /data:/i,
    /on\w+\s*=/i,
    /expression\s*\(/i,
    /alert\s*\(/i,
    /confirm\s*\(/i,
    /prompt\s*\(/i,
    /eval\s*\(/i,
    /\<iframe/i,
    /\<object/i,
    /\<embed/i,
    /\<style/i,
    /\<link/i
  ];

  return !dangerousPatterns.some(pattern => pattern.test(str));
};

module.exports = {
  sanitize,
  isCleanInput
};

