  message: 'Too many requests from this IP, please try again later.',
  standardHeaders: true, // Return rate limit info in the RateLimit-* headers
  legacyHeaders: false, // Disable the X-RateLimit-* headers
});

// Apply rate limiting to all requests
app.use(limiter);

// Parse JSON bodies
app.use(express.json({ limit: '10kb' })); // Limit request size
app.use(express.urlencoded({ extended: true, limit: '10kb' }));

// Environment variables
const PORT = process.env.PORT || 3000;
const NODE_ENV = process.env.NODE_ENV || 'development';

// Enhanced health check with environment info (safe)
app.get('/health', (req, res) => {
  // Log the health check request
  console.log(`${new Date().toISOString()} - Health check requested from ${req.ip}`);

  res.json({ 
    status: 'ok', 
    timestamp: new Date().toISOString(),
    environment: NODE_ENV,
    version: '1.0.0'
  });
});

// Users endpoint with input validation and safe data handling
app.get('/users', (req, res) => {
  try {
    // Log the request
    console.log(`${new Date().toISOString()} - Users requested from ${req.ip}`);

    // Input validation
    const page = parseInt(req.query.page) || 1;
    const limit = parseInt(req.query.limit) || 10;

    // Validate inputs
    if (page < 1) {
      return res.status(400).json({
        error: 'Page number must be a positive integer'
      });
    }

    if (limit < 1 || limit > 100) {
      return res.status(400).json({
        error: 'Limit must be between 1 and 100'
      });
    }

    // Mock user data (in real app, this would come from a database)
    const mockUsers = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    // In a real application, you would paginate the data from your database
    // For now, we'll just return all users with pagination info
    const total = mockUsers.length;
    const totalPages = Math.ceil(total / limit);

    res.json({
      data: mockUsers,
      pagination: {
        currentPage: page,
        totalPages,
        total,
        limit
      }
    });

  } catch (error) {
    console.error(`${new Date().toISOString()} - Error in /users endpoint:`, error);
    res.status(500).json({
      error: 'Internal server error'
    });
  }
});

// 404 handler for undefined routes
app.use('*', (req, res) => {
  res.status(404).json({
    error: `Route ${req.method} ${req.url} not found`
  });
});

// Global error handler
app.use((error, req, res, next) => {
  console.error(`${new Date().toISOString()} - Unhandled error:`, error);

  // Don't leak error details in production
  const errorResponse = NODE_ENV === 'production' 
    ? { error: 'Internal server error' }
    : { error: error.message, stack: error.stack };

  res.status(500).json(errorResponse);
});

