const express = require('express');
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');
const cors = require('cors');
const { body, validationResult } = require('express-validator');

const app = express();

// Security middleware
app.use(helmet()); // Sets various HTTP headers for security

// Rate limiting to prevent brute force attacks
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // Limit each IP to 100 requests per windowMs
  message: {
    error: 'Too many requests from this IP, please try again later.'
  }
});
app.use(limiter);

// Enable CORS with restrictive policies
app.use(cors({
  origin: process.env.ALLOWED_ORIGINS?.split(',') || ['http://localhost:3000'],
  credentials: true
}));

// Parse JSON bodies
app.use(express.json({
  limit: '10kb' // Prevent large payloads
}));

// Health check endpoint
app.get('/health', (req, res) => {
  try {
    res.json({ 
      status: 'ok', 
      timestamp: new Date().toISOString() 
    });
  } catch (error) {
    console.error('Health check error:', error);
    res.status(500).json({ 
      error: 'Health check failed',
      timestamp: new Date().toISOString() 
    });
  }
});

// Users endpoint with potential ID parameter
app.get('/users', [
  // Validate query parameters if present
  (req, res, next) => {
    if (req.query.id) {
      const id = parseInt(req.query.id);
      if (isNaN(id) || id <= 0) {
        return res.status(400).json({
          error: 'Invalid user ID parameter'
        });
      }
    }
    next();
  }
], (req, res) => {
  try {
    // Sample data
    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    // Filter by ID if requested
    if (req.query.id) {
      const id = parseInt(req.query.id);
      const user = users.find(u => u.id === id);
      if (!user) {
        return res.status(404).json({
          error: 'User not found'
        });
      }
      return res.json([user]);
    }

    res.json(users);
  } catch (error) {
    console.error('Error fetching users:', error);
    res.status(500).json({ 
      error: 'Internal server error'
    });
  }
});

// 404 handler for undefined routes
app.use('*', (req, res) => {
  res.status(404).json({
    error: `Route ${req.method} ${req.url} not found`
  });
});

// Global error handler
app.use((error, req, res, next) => {
  console.error('Uncaught error:', error);

  // Handle validation errors
  if (error.array) {
    return res.status(400).json({
      error: 'Validation failed',
      details: error.array()
    });
  }

  // Handle known error types
  if (error.name === 'UnauthorizedError') {
    return res.status(401).json({
      error: 'Unauthorized access'
    });
  }

  // Default to generic error message
  res.status(500).json({ 
    error: 'Internal server error'
  });
});

// Handle unhandled promise rejections
process.on('unhandledRejection', (error) => {
  console.error('Unhandled Promise Rejection:', error);
  // In a production app, you might want to gracefully shutdown here
});

// Handle uncaught exceptions
process.on('uncaughtException', (error) => {
  console.error('Uncaught Exception:', error);
  // Close server and exit process
  process.exit(1);
});

const PORT = process.env.PORT || 3000;
const server = app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

// Handle graceful shutdown
process.on('SIGTERM', () => {
  console.log('SIGTERM received, shutting down gracefully');
  server.close(() => {
    console.log('Process terminated');
  });
});

process.on('SIGINT', () => {
  console.log('SIGINT received, shutting down gracefully');
  server.close(() => {
    console.log('Process terminated');
  });
});

module.exports = app;

const express = require('express');
const app = express();

// Parse JSON bodies with size limit to prevent abuse
app.use(express.json({
  limit: '10kb'
}));

// Security: Set basic security headers
app.use((req, res, next) => {
  // Prevent XSS attacks
  res.setHeader('X-Content-Type-Options', 'nosniff');
  res.setHeader('X-Frame-Options', 'DENY');
  res.setHeader('X-XSS-Protection', '1; mode=block');

  // Prevent clickjacking
  res.setHeader('X-Frame-Options', 'DENY');

  // Enable HSTS
  res.setHeader('Strict-Transport-Security', 'max-age=31536000; includeSubDomains');

  next();
});

// Rate limiting with simple in-memory storage
const requestCounts = new Map();
const WINDOW_DURATION = 15 * 60 * 1000; // 15 minutes
const MAX_REQUESTS = 100;

app.use((req, res, next) => {
  const ip = req.ip || req.connection.remoteAddress;
  const now = Date.now();

  // Clean up old entries
  if (requestCounts.size > 1000) {
    // Rough cleanup if we have too many entries
    for (const [key, value] of requestCounts) {
      if (now - value.timestamp > WINDOW_DURATION) {
        requestCounts.delete(key);
      }
    }
  }

  const record = requestCounts.get(ip) || { count: 0, timestamp: now };

  // Reset counter if outside window
  if (now - record.timestamp > WINDOW_DURATION) {
    record.count = 0;
    record.timestamp = now;
  }

  record.count++;
  requestCounts.set(ip, record);

  // Check if rate limit exceeded
  if (record.count > MAX_REQUESTS) {
    return res.status(429).json({
      error: 'Too many requests from this IP, please try again later.'
    });
  }

  next();
});

// Input validation helper
function validateUserId(id) {
  const numId = parseInt(id);
  return !isNaN(numId) && numId > 0 && isFinite(id);
}

// Health check endpoint with error handling
app.get('/health', (req, res) => {
  try {
    res.json({ 
      status: 'ok', 
      timestamp: new Date().toISOString() 
    });
  } catch (error) {
    console.error('Health check error:', error);
    res.status(500).json({ 
      error: 'Health check failed'
    });
  }
});

// Users endpoint with input validation
app.get('/users', (req, res) => {
  try {
    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    // Handle optional ID parameter
    if (req.query.id !== undefined) {
      // Validate the ID parameter
      if (!validateUserId(req.query.id)) {
        return res.status(400).json({
          error: 'Invalid user ID parameter'
        });
      }

      const id = parseInt(req.query.id);
      const user = users.find(u => u.id === id);

      if (!user) {
        return res.status(404).json({
          error: 'User not found'
        });
      }

      return res.json([user]);
    }

    res.json(users);
  } catch (error) {
    console.error('Error fetching users:', error);
    res.status(500).json({ 
      error: 'Internal server error'
    });
  }
});

// 404 handler for undefined routes
app.use('*', (req, res) => {
  res.status(404).json({
    error: `Route ${req.method} ${req.url} not found`
  });
});

// Global error handler middleware
app.use((error, req, res, next) => {
  console.error('Unhandled error:', error);
  res.status(500).json({ 
    error: 'Internal server error'
  });
});

// Handle unhandled promise rejections
process.on('unhandledRejection', (error) => {
  console.error('Unhandled Promise Rejection:', error);
});

// Handle uncaught exceptions
process.on('uncaughtException', (error) => {
  console.error('Uncaught Exception:', error);
  process.exit(1);
});

// Graceful shutdown
const PORT = process.env.PORT || 3000;
const server = app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

process.on('SIGTERM', () => {
  console.log('SIGTERM received, shutting down gracefully');
  server.close(() => {
    console.log('Process terminated');
  });
});

process.on('SIGINT', () => {
  console.log('SIGINT received, shutting down gracefully');
  server.close(() => {
    console.log('Process terminated');
  });
});

module.exports = app;

